style:
h3 {
  text-align: center;
  font-size: 18px;
  font-weight: 600;
  color: #666;
  margin: 15px 0 10px;
  padding: 0 10px;
  line-height: 1.4;
}
/* 第一个p标签（简介）居中 */
 .info p{
  text-align: center;
  font-size: 14px;
  color: #444;
  margin-bottom: 5px;
  padding: 0 10px;
  max-width: 95%; 
  margin-left: auto; 
  margin-right: auto;
}
/* 左右两列容器 */
.info-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 10px 20px;
  margin: 0 auto;
  max-width: 500px;
  width: 100%;
  padding: 0 35px;
  box-sizing: border-box;
}
/* 左右列各占50%宽度 */
.info-column {
  flex: 1 0 45%;
}
/* 列内p标签样式 */
.info-column p {
  text-align: left;
  font-size: 13px;
  color: #555;
  margin-bottom: 5px;
  margin-right: 8px;
  padding: 0px 0;
  position: relative;
}
.info-column p::before {
  content: "•";
  color: #888;
  font-size: 13px;
  margin-right: 5px;
}
